package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bruto.RkmPrestatieVerhouding;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckRegimeAchterstal;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelGegevensSingleOpper;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AstWrkwBv;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.BEGROTING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

@Slf4j
public class BerekenBvAchterstal extends AbstractBerekenBv {

    public BerekenBvAchterstal(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        initFiscaleConstanten(rekenTijd);

        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            if (BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                berekenBvAchterstal(mainContext, opdracht, rekenTijd);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenBvAchterstal(RekenContext mainContext, Opdracht opdracht, RekenTijd rekenTijd) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        Money belastbaarAchterstal = getBelastbaar(BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY, BELASTBAAR_ACHTERSTAL_KEY, loonElementen);

        PersoonsDataManager dataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        Opper opperLaatsteGegevens = dataManager.getOpperOpDatum(opdracht, rekenTijd.rekenDatum);

        Money bedrijfsvoorheffingAchterstal = berekenBVAchterstal(opdrachtContext, opperLaatsteGegevens, belastbaarAchterstal);
        herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY, bedrijfsvoorheffingAchterstal, BELASTBAAR_ACHTERSTAL_KEY,
                belastbaarAchterstal, loonElementen);
        log.trace("opdrachtsElementen:{}", loonElementen);
    }

    @Override
    protected void herverdeelBedrijfsvoorheffing(
            MoneyKey bvKey, Money bedrijfsvoorheffing, MoneyKey bbKey, Money totaalBelastbaar,
            Collection<LoonElement> loonElementen) {
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(bvKey, bedrijfsvoorheffing, bbKey, totaalBelastbaar, loonElementen, CheckRegimeAchterstal.DEFAULT);
    }

    protected Money berekenBVAchterstal(RekenContext opdrachtContext, Opper opper, Money belastbaar) {
        AstWrkwBv fiscaleWerkwijze = opper.getOpdrachtFiscaliteit().getWerkwijzeAchterstal();
        Money bedrijfsvoorheffing = Money.ZERO;
        log.debug("{};belastbaar:{};fiscaleWerkwijze:{}", LogTools.toSimpleLog(opper.getOpdracht()), belastbaar, fiscaleWerkwijze);
        if (belastbaar.signum() > 0 && !uitzonderingJobStudent(opper, fiscaleWerkwijze, opdrachtContext.getRekenTijd())) {
            switch (fiscaleWerkwijze) {
                case BAREMA_GN_KUMUL:
                    bedrijfsvoorheffing = berekenBVAchterstalBaremaGeenKumul(opdrachtContext, belastbaar);
                    break;
                case PERCENTAGE:
                    bedrijfsvoorheffing = berekenBVAchterstalPercentage(opper, belastbaar);
                    break;
                case BEDRAG:
                    bedrijfsvoorheffing = opper.getOpdrachtFiscaliteit().getBedragAchterstal();
                    break;
                case BAREMA_INV_PVH:
                    bedrijfsvoorheffing = berekenBVAchterstalBaremaInvPvh(opdrachtContext, opper, belastbaar);
                    break;
                default:
                    RegulManager regulManager = opdrachtContext.getUnchecked(REGUL_MANAGER_KEY);
                    regulManager.doRegulException(opper.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
                    break;
            }
        }
        log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);
        return bedrijfsvoorheffing;
    }

    private boolean uitzonderingJobStudent(Opper opper, AstWrkwBv fiscaleWerkwijze, RekenTijd rekenTijd) {
        return WerknemersKengetalFactory.isStudent(opper, RkmTijdperk.getTijdperk(rekenTijd.rekenDatum)) && fiscaleWerkwijze != AstWrkwBv.PERCENTAGE &&
                fiscaleWerkwijze != AstWrkwBv.BEDRAG;
    }

    private Money berekenBVAchterstalBaremaGeenKumul(RekenContext opdrachtContext, Money belastbaar) {
        Persoon persoon = opdrachtContext.getUnchecked(PERSOON_KEY);
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(REKENTIJD_KEY);
        Money jaarInkomen = opdrachtContext.getMoney(BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY);
        return berekenBVAchterstalBarema(persoon, jaarInkomen, belastbaar, rekenTijd);
    }

    private Money berekenBVAchterstalPercentage(Opper opper, Money belastbaar) {
        BigDecimal percentage = opper.getOpdrachtFiscaliteit().getPercentageAchterstal().movePointLeft(2);
        log.debug("percentage:{}", percentage);
        return belastbaar.multiply(percentage).round(2);
    }

    private Money berekenBVAchterstalBaremaInvPvh(RekenContext opdrachtContext, Opper opper, Money belastbaar) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(REKENTIJD_KEY);
        RegulManager regulManager = opdrachtContext.getUnchecked(REGUL_MANAGER_KEY);
        Persoon persoon = opdrachtContext.getUnchecked(PERSOON_KEY);

        boolean begroting = opdrachtContext.getBoolean(BEGROTING_KEY);
        BigDecimal prestatieVerhouding = RkmPrestatieVerhouding.bepaalTheoretisch(new SleutelGegevensSingleOpper(opper), regulManager, begroting);
        Money jaarInkomen = opdrachtContext.getMoney(BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY);
        if (prestatieVerhouding.signum() == 0) {
            prestatieVerhouding = BigDecimal.ONE;
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.BASISBETAALBREUK_NUL);
        }
        Money jaarInkomenInvPvh = jaarInkomen.divide(prestatieVerhouding);
        return berekenBVAchterstalBarema(persoon, jaarInkomenInvPvh, belastbaar, rekenTijd);
    }

}
